import{_ as a,o as s,c as o,a2 as r}from"./chunks/framework.D2pTuMig.js";const v=JSON.parse('{"title":"Co-Branded Contest (publisher)","description":"","frontmatter":{"title":"Co-Branded Contest (publisher)"},"headers":[],"relativePath":"docs/fr/publishers/co-branded-contest/index.md","filePath":"docs/fr/publishers/co-branded-contest/index.md"}'),t={name:"docs/fr/publishers/co-branded-contest/index.md"};function i(n,e,d,c,u,l){return s(),o("div",null,[...e[0]||(e[0]=[r('<h1 id="jeu-concours-co-brande" tabindex="-1">Jeu Concours Co-brandé <a class="header-anchor" href="#jeu-concours-co-brande" aria-label="Permalink to &quot;Jeu Concours Co-brandé&quot;">​</a></h1><p>Animez votre communauté tout en monétisant votre audience grâce à des opérations financées par les marques.</p><p><a href="setup-guide" class="btn btn-primary">Guide de mise en place →</a></p><h2 id="pourquoi-proposer-ce-format" tabindex="-1">Pourquoi proposer ce format ? <a class="header-anchor" href="#pourquoi-proposer-ce-format" aria-label="Permalink to &quot;Pourquoi proposer ce format ?&quot;">​</a></h2><div class="gi-value-grid"><div class="gi-value-card"><strong>💰 Revenus Média</strong><p>L&#39;annonceur finance tout — dotations, lots, coûts opérationnels. Source de revenus 100% additionnel, sans risque pour vous.</p></div><div class="gi-value-card"><strong>🎉 Animation Commerciale</strong><p>Offrez une expérience ludique et des cadeaux attractifs à vos clients. Cela dynamise votre site et vos newsletters.</p></div><div class="gi-value-card"><strong>📊 Qualification Data</strong><p>Réactivez des clients inactifs et collectez des leads opt-in ultra-qualifiés — qualifiés par le comportement d&#39;achat de votre propre audience.</p></div></div><h2 id="le-concept" tabindex="-1">Le Concept <a class="header-anchor" href="#le-concept" aria-label="Permalink to &quot;Le Concept&quot;">​</a></h2><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>Vous hébergez une <strong>page de jeu sur votre site</strong> (ou une page dédiée externe). Vous dirigez du trafic dessus via vos canaux habituels (Email, Push, Social). L&#39;Annonceur récupère les leads &quot;Opt-in&quot; à la fin de l&#39;opération.</p></div><h2 id="pourquoi-passer-par-getinside" tabindex="-1">Pourquoi passer par getinside ? <a class="header-anchor" href="#pourquoi-passer-par-getinside" aria-label="Permalink to &quot;Pourquoi passer par getinside ?&quot;">​</a></h2><div class="gi-value-grid"><div class="gi-value-card"><strong>⚖️ Sécurité Juridique</strong><p>La collecte de data partagée est complexe (RGPD). Nous fournissons les modèles de mentions légales et de cases à cocher validés par des juristes.</p></div><div class="gi-value-card"><strong>🤝 Gestion des Dotations</strong><p>Vous ne gérez pas l&#39;envoi des lots aux gagnants — c&#39;est l&#39;Annonceur qui s&#39;en charge. Votre responsabilité s&#39;arrête à l&#39;hébergement du jeu.</p></div></div>',9)])])}const g=a(t,[["render",i]]);export{v as __pageData,g as default};
